import{_ as p,C as c,o as s,c as h,j as a,a as t,b as r,w as o,E as n,a3 as l,a2 as d}from"./chunks/framework._O8Cueap.js";const y=JSON.parse('{"title":"Workflows","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/workflows.md","filePath":"concepts/workflows.md"}'),g={name:"concepts/workflows.md"};function u(m,e,k,b,f,w){const i=c("Mermaid");return s(),h("div",null,[e[3]||(e[3]=a("h1",{id:"workflows",tabindex:"-1"},[t("Workflows "),a("a",{class:"header-anchor",href:"#workflows","aria-label":'Permalink to "Workflows"'},"​")],-1)),e[4]||(e[4]=a("p",null,[t("A "),a("strong",null,"workflow"),t(" is an ordered sequence of steps, each executed as a separate Copilot session. Steps pass output forward, enabling complex multi-stage reasoning.")],-1)),e[5]||(e[5]=a("h2",{id:"workflow-structure",tabindex:"-1"},[t("Workflow Structure "),a("a",{class:"header-anchor",href:"#workflow-structure","aria-label":'Permalink to "Workflow Structure"'},"​")],-1)),(s(),r(l,null,{default:o(()=>[n(i,{id:"mermaid-9",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20T%5B%22Trigger%3Cbr%2F%3E(schedule%20%2F%20webhook%20%2F%20event%20%2F%20Jira)%22%5D%20--%3E%20S1%5BStep%201%5D%0A%20%20%20%20S1%20--%3E%7Cprecedent_output%7C%20S2%5BStep%202%5D%0A%20%20%20%20S2%20--%3E%7Cprecedent_output%7C%20S3%5B%22Step%20...%22%5D%0A%20%20%20%20S3%20--%3E%7Cprecedent_output%7C%20SN%5BStep%20N%5D%0A%20%20%20%20SN%20--%3E%20R%5B%22Execution%3Cbr%2F%3EResult%22%5D%0A%0A%20%20%20%20style%20T%20fill%3A%23FF9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20R%20fill%3A%234CAF50%2Ccolor%3A%23fff%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[t(" Loading... ",-1)])]),_:1})),e[6]||(e[6]=d(`<div class="mermaid-source" data-mermaid-source=""></div><p>A workflow is a linear pipeline of steps. Each step runs as an independent Copilot session. The output of step <em>N</em> becomes <span><code>{{ precedent_output }}</code></span> for step <em>N+1</em>.</p><p>Each workflow has:</p><ul><li><strong>Name &amp; description</strong></li><li><strong>Labels</strong> — filterable tags for organizing workflows (e.g., <code>production</code>, <code>daily</code>, <code>reporting</code>)</li><li><strong>Default agent</strong> — used when a step doesn&#39;t specify its own</li><li><strong>Default model</strong> — selected from admin-configured models (e.g., <code>claude-sonnet-4-6</code>, <code>gpt-5.4</code>)</li><li><strong>Default reasoning effort</strong> — <code>high</code>, <code>medium</code>, or <code>low</code></li><li><strong>Worker runtime</strong> — workflow default for step dispatch: <code>static</code> (BullMQ worker pool) or <code>ephemeral</code> (one Kubernetes pod per step)</li><li><strong>Step allocation timeout</strong> — how long a step may remain pending while waiting for a runtime to become ready</li><li><strong>Scope</strong> — <code>user</code> (private) or <code>workspace</code> (shared, admin-only creation)</li><li><strong>Version</strong> — auto-incremented on every edit</li></ul><h2 id="version-history" tabindex="-1">Version History <a class="header-anchor" href="#version-history" aria-label="Permalink to &quot;Version History&quot;">​</a></h2><p>Workflows keep immutable version history for the workflow definition, ordered steps, and triggers.</p><ul><li>The latest editable page lives at <code>/{workspace}/workflows/:id</code></li><li>Historical snapshots live at <code>/{workspace}/workflows/:id/v/:version</code></li><li>Historical pages are read-only and are the target for execution detail links, so users can inspect the exact workflow version that produced an execution</li></ul><p>Workflow history captures the state before each edit so older versions remain navigable even after later changes.</p><p>Trigger create, update, and delete operations also increment the workflow version, whether they originate from the UI, the API, or built-in agent tools.</p><h2 id="execution-detail-view" tabindex="-1">Execution Detail View <a class="header-anchor" href="#execution-detail-view" aria-label="Permalink to &quot;Execution Detail View&quot;">​</a></h2><p>Workflow execution detail pages summarize the run with styled metadata blocks for trigger source, workflow, runtime, start time, duration, and step progress.</p><p>Expanded step panels use a dark detail surface so logs, prompt text, reasoning output, and markdown previews remain readable. The selected step tab intentionally switches to a light active state for contrast, and markdown tables/code blocks are themed consistently across Output and Reasoning tabs.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><p>Each step defines:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Human-readable step label</td></tr><tr><td><strong>Prompt Template</strong></td><td>The markdown prompt sent to the Copilot session</td></tr><tr><td><strong>Agent</strong></td><td>Optional override (defaults to workflow&#39;s agent)</td></tr><tr><td><strong>Model</strong></td><td>Optional override (defaults to workflow&#39;s model)</td></tr><tr><td><strong>Reasoning Effort</strong></td><td>Optional override (<code>high</code>, <code>medium</code>, <code>low</code>)</td></tr><tr><td><strong>Worker Runtime</strong></td><td>Optional override (<code>static</code>, <code>ephemeral</code>) that falls back to the workflow default</td></tr><tr><td><strong>Timeout</strong></td><td>Max execution time in seconds (30–3600, default: 300)</td></tr></tbody></table><h3 id="resolution-priority" tabindex="-1">Resolution Priority <a class="header-anchor" href="#resolution-priority" aria-label="Permalink to &quot;Resolution Priority&quot;">​</a></h3><p>For Agent, Model, Reasoning Effort, and Worker Runtime, the engine resolves in this order:</p><ol><li><strong>Step-level override</strong> (if set)</li><li><strong>Workflow-level default</strong> (if set)</li><li><strong>Platform default</strong> (for model: <code>DEFAULT_AGENT_MODEL</code> env var, defaults to <code>gpt-4.1</code>; for runtime: <code>static</code>)</li></ol><h3 id="worker-runtime" tabindex="-1">Worker Runtime <a class="header-anchor" href="#worker-runtime" aria-label="Permalink to &quot;Worker Runtime&quot;">​</a></h3><p>Workflow dispatch resolves the runtime per step:</p><table tabindex="0"><thead><tr><th>Runtime</th><th>Behavior</th></tr></thead><tbody><tr><td><strong><code>static</code></strong></td><td>Enqueue the step on the shared <code>agent-step-execution</code> BullMQ queue for long-running worker instances. The step stays <code>pending</code> until a static worker starts it.</td></tr><tr><td><strong><code>ephemeral</code></strong></td><td>Create a dedicated Kubernetes pod for that step. The step stays <code>pending</code> while the pod is created and becomes ready.</td></tr></tbody></table><p>The resolved runtime is snapshotted onto each <code>workflow_execution</code>, so execution history keeps the original dispatch mode even if the workflow is edited later.</p><h3 id="step-allocation-timeout" tabindex="-1">Step Allocation Timeout <a class="header-anchor" href="#step-allocation-timeout" aria-label="Permalink to &quot;Step Allocation Timeout&quot;">​</a></h3><p>Each workflow defines a <strong>Step Allocation Timeout</strong> in seconds.</p><ul><li>A <strong>static</strong> step uses this timeout while waiting for a shared worker to start the job.</li><li>An <strong>ephemeral</strong> step uses this timeout while waiting for its dedicated pod to be created and reach a runnable state.</li><li>While allocation is pending, the step remains <code>pending</code> and the workflow execution remains <code>running</code>.</li><li>The workflow only fails when allocation exceeds the configured timeout.</li></ul><h3 id="jinja2-prompt-templates" tabindex="-1">Jinja2 Prompt Templates <a class="header-anchor" href="#jinja2-prompt-templates" aria-label="Permalink to &quot;Jinja2 Prompt Templates&quot;">​</a></h3><p>Prompt templates use <strong>Jinja2 templating</strong> (powered by Nunjucks). Available variables:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><span><code>{{ precedent_output }}</code></span></td><td>Output from the previous step</td></tr><tr><td><span><code>{{ properties.KEY }}</code></span></td><td>Agent/user/workspace property values</td></tr><tr><td><span><code>{{ credentials.KEY }}</code></span></td><td>Agent/user/workspace credential values</td></tr><tr><td><span><code>{{ env.KEY }}</code></span></td><td>Variables marked for env injection</td></tr><tr><td><span><code>{{ inputs.KEY }}</code></span></td><td>Webhook parameter / manual run input values</td></tr></tbody></table><p>For the full template variable reference, see <a href="/open-agent-orchestra/reference/template-variables.html">Template Variables</a>.</p><p>You can use any Jinja2 features: conditionals, loops, filters, etc.</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Analyze the market for {{ properties.MARKET_SYMBOL }}.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Current risk limit: {{ properties.MAX_RISK_PERCENT }}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% if precedent_output %}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Previous analysis:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{{ precedent_output }}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% endif %}</span></span></code></pre></div><h3 id="example-3-step-workflow" tabindex="-1">Example: 3-Step Workflow <a class="header-anchor" href="#example-3-step-workflow" aria-label="Permalink to &quot;Example: 3-Step Workflow&quot;">​</a></h3><p><strong>Step 1 — &quot;Analyze Market&quot;:</strong></p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Analyze the current market conditions for AAPL, GOOG, MSFT.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">For each symbol, provide:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Current trend (bullish/bearish/neutral)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Key support/resistance levels</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Recent news impact</span></span></code></pre></div><p><strong>Step 2 — &quot;Make Trade Decisions&quot;:</strong></p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Based on the following market analysis, decide which trades to make:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{{ precedent_output }}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">For each recommended trade, provide: symbol, side, quantity, and reasoning.</span></span></code></pre></div><p><strong>Step 3 — &quot;Write Blog Post&quot;:</strong></p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Write a brief market commentary blog post based on the following trade decisions:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{{ precedent_output }}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Write in a professional but approachable tone.</span></span></code></pre></div><h2 id="what-happens-on-the-agent" tabindex="-1">What Happens on the Agent <a class="header-anchor" href="#what-happens-on-the-agent" aria-label="Permalink to &quot;What Happens on the Agent&quot;">​</a></h2><p>When a step is dispatched to an agent worker, the following pipeline runs inside the agent instance:</p>`,40)),(s(),r(l,null,{default:o(()=>[n(i,{id:"mermaid-356",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20START%5BAgent%20Worker%20picks%20up%20step%5D%20--%3E%20VARS%5BLoad%20%26%20merge%20variables%3Cbr%2F%3Eworkspace%20%E2%86%92%20user%20%E2%86%92%20agent%5D%0A%20%20%20%20VARS%20--%3E%20WORKSPACE%5BPrepare%20agent%20workspace%3Cbr%2F%3EGit%20clone%20or%20DB%20file%20read%5D%0A%20%20%20%20WORKSPACE%20--%3E%20AGENT%5BLoad%20agent%20markdown%3Cbr%2F%3Epersonality%20%2B%20instructions%5D%0A%20%20%20%20AGENT%20--%3E%20SKILLS%5BLoad%20skill%20files%3Cbr%2F%3Eexplicit%20paths%20or%20directory%20scan%5D%0A%20%20%20%20SKILLS%20--%3E%20RENDER%5BRender%20Jinja2%20prompt%20template%3Cbr%2F%3Ewith%20variables%2C%20inputs%2C%20precedent_output%5D%0A%20%20%20%20RENDER%20--%3E%20MCP%5BSpawn%20MCP%20servers%3Cbr%2F%3EDB%20configs%20%2B%20JSON%20template%5D%0A%20%20%20%20MCP%20--%3E%20TOOLS%5BLoad%20tools%3Cbr%2F%3Ebuilt-in%20%2B%20MCP%5D%0A%20%20%20%20TOOLS%20--%3E%20SESSION%5BCreate%20Copilot%20Session%3Cbr%2F%3Esystem%20message%20%2B%20tools%20%2B%20model%5D%0A%20%20%20%20SESSION%20--%3E%20EXEC%5BSend%20prompt%20%26%20wait%20for%20response%5D%0A%20%20%20%20EXEC%20--%3E%20WRITE%5BWrite%20output%20%2B%20reasoning%20trace%5D%0A%20%20%20%20WRITE%20--%3E%20CLEANUP%5BCleanup%3Cbr%2F%3EMCP%20processes%2C%20workspace%2C%20lock%5D%0A%0A%20%20%20%20style%20START%20fill%3A%23FF9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20SESSION%20fill%3A%239C27B0%2Ccolor%3A%23fff%0A%20%20%20%20style%20WRITE%20fill%3A%234CAF50%2Ccolor%3A%23fff%0A"})]),fallback:o(()=>[...e[1]||(e[1]=[t(" Loading... ",-1)])]),_:1})),e[7]||(e[7]=d(`<div class="mermaid-source" data-mermaid-source=""></div><p>For full details on each phase, see <a href="/open-agent-orchestra/concepts/agent-steps.html">Agent Steps</a>.</p><h2 id="triggers" tabindex="-1">Triggers <a class="header-anchor" href="#triggers" aria-label="Permalink to &quot;Triggers&quot;">​</a></h2><p>Triggers define <strong>when</strong> a workflow executes. Workflows can also be run manually from the UI when a webhook trigger is configured.</p><h3 id="trigger-types" tabindex="-1">Trigger Types <a class="header-anchor" href="#trigger-types" aria-label="Permalink to &quot;Trigger Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Configuration</th></tr></thead><tbody><tr><td><strong>Schedule</strong></td><td>Recurring execution</td><td>Cron expression (e.g., <code>0 9 * * 1-5</code>)</td></tr><tr><td><strong>Exact Datetime</strong></td><td>One-shot at a specific time</td><td>ISO 8601 datetime (auto-deactivates after firing)</td></tr><tr><td><strong>Webhook</strong></td><td>Trigger from user-provided inputs and reusable parameter definitions</td><td>Path + parameter definitions</td></tr><tr><td><strong>System Event</strong></td><td>React to platform events</td><td>Event name + optional scope + conditions</td></tr><tr><td><strong>Jira Changes Notification</strong></td><td>Register an Atlassian dynamic webhook filtered by JQL</td><td>Jira site URL + OAuth 2.0 credential references + JQL + Jira event list</td></tr><tr><td><strong>Jira Polling</strong></td><td>Poll Jira search results on an interval with overlap-window dedupe</td><td>Jira site URL + API token or OAuth 2.0 credential references + JQL + interval</td></tr></tbody></table><p>The workflow create and detail pages now use a <strong>trigger catalog</strong> plus an inline editor, so new trigger types can be added without changing the page layout. On the workflow detail page, the catalog opens from the right edge of the trigger tab, while editing an existing trigger converts that specific trigger card into the edit form instead of opening a second detached form.</p><p>Existing trigger cards also surface sanitized runtime summaries such as Jira registration state, webhook expiration, last sync time, or the last successful polling time.</p><p>Jira trigger credential references are selected from workflow-visible credential variables (workspace or user scope), not entered as free text.</p><p>Saved trigger cards expose a <strong>Test Connectivity</strong> action. For Jira notification triggers, the connectivity test verifies Jira webhook registration and probes the hosted callback URL. For Jira polling triggers, it executes the configured JQL with the saved credentials.</p><p>Triggers can be <strong>edited in place</strong>. Use <code>PUT /api/triggers/:id</code> (or the inline editor in the workflow UI) to update the trigger type, configuration, or enabled state. Webhook paths must still be unique across all webhook triggers.</p><h3 id="manual-run" tabindex="-1">Manual Run <a class="header-anchor" href="#manual-run" aria-label="Permalink to &quot;Manual Run&quot;">​</a></h3><p>The <strong>Manual Run</strong> button in the UI allows authenticated users to trigger a workflow directly. It is available when the workflow has at least one active <strong>webhook trigger</strong>.</p><p>When clicked, the UI shows input fields based on the webhook trigger&#39;s <strong>parameter definitions</strong>. Required parameters must be filled in before the run starts. The inputs are available in prompt templates as <span><code>{{ inputs.PARAM_NAME }}</code></span>.</p><p>Manual Run calls <code>POST /api/workflows/:id/run</code>, which inserts a <code>webhook.received</code> event into the event system. The Controller picks it up in the next poll cycle and enqueues the execution.</p><h3 id="webhook-parameters" tabindex="-1">Webhook Parameters <a class="header-anchor" href="#webhook-parameters" aria-label="Permalink to &quot;Webhook Parameters&quot;">​</a></h3><p>Webhook triggers support <strong>user-defined parameters</strong>:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Parameter key (used in templates as <span><code>{{ inputs.name }}</code></span>)</td></tr><tr><td><strong>Required</strong></td><td>If <code>true</code>, the parameter must be provided (validated on webhook and manual run)</td></tr><tr><td><strong>Description</strong></td><td>Optional help text shown in the Manual Run dialog</td></tr></tbody></table><p>When a webhook fires (<code>POST /api/webhooks/:path</code>), the request body is validated against the parameter definitions. Only defined parameters are passed through as <code>inputs</code>.</p><h3 id="webhook-security" tabindex="-1">Webhook Security <a class="header-anchor" href="#webhook-security" aria-label="Permalink to &quot;Webhook Security&quot;">​</a></h3><ul><li><strong>HMAC-SHA256</strong> signature verification</li><li><strong>Personal Access Token</strong> (PAT) with <code>webhook:trigger</code> scope</li><li><strong>5-minute replay protection</strong></li><li><strong>Event ID deduplication</strong></li></ul><h3 id="jira-changes-notification" tabindex="-1">Jira Changes Notification <a class="header-anchor" href="#jira-changes-notification" aria-label="Permalink to &quot;Jira Changes Notification&quot;">​</a></h3><p>Jira Changes Notification uses Atlassian dynamic webhooks instead of OAO polling the Jira REST API directly.</p><ul><li><code>PUBLIC_API_BASE_URL</code> must point at the public OAO API origin because Jira must call back into <code>/api/jira-webhooks/:triggerId?token=...</code></li><li>Jira API tokens are <strong>not</strong> enough for dynamic webhook registration; this trigger requires Jira OAuth 2.0 credentials</li><li>OAO refreshes Jira webhook registrations before they expire and dedupes repeated Atlassian delivery identifiers</li></ul><h3 id="jira-polling" tabindex="-1">Jira Polling <a class="header-anchor" href="#jira-polling" aria-label="Permalink to &quot;Jira Polling&quot;">​</a></h3><p>Jira Polling is designed for cases where webhook registration is not available or not desired.</p><ul><li>Supports Jira API tokens or Jira OAuth 2.0 credentials</li><li>Queries Jira search on the configured interval</li><li>Uses an overlap window plus a recent-issue map so eventual consistency and controller restarts do not create obvious gaps or duplicate executions</li></ul><h3 id="cron-expression-examples" tabindex="-1">Cron Expression Examples <a class="header-anchor" href="#cron-expression-examples" aria-label="Permalink to &quot;Cron Expression Examples&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0 9 * * 1-5    → 9:00 AM every weekday</span></span>
<span class="line"><span>*/30 * * * *   → Every 30 minutes</span></span>
<span class="line"><span>0 0 1 * *      → First day of every month at midnight</span></span></code></pre></div><h3 id="event-trigger" tabindex="-1">Event Trigger <a class="header-anchor" href="#event-trigger" aria-label="Permalink to &quot;Event Trigger&quot;">​</a></h3><p>React to system events with optional data matching:</p>`,31)),(s(),r(l,null,{default:o(()=>[n(i,{id:"mermaid-608",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20SE%5BSystem%20Event%3Cbr%2F%3Ee.g.%20agent.created%5D%20--%3E%7Cmatch%7C%20ET%5BEvent%20Trigger%3Cbr%2F%3Econditions%20check%5D%0A%20%20%20%20ET%20--%3E%20WF%5BWorkflow%20Execution%5D%0A"})]),fallback:o(()=>[...e[2]||(e[2]=[t(" Loading... ",-1)])]),_:1})),e[8]||(e[8]=d('<div class="mermaid-source" data-mermaid-source="Z3JhcGggTFIKICAgIFNFW1N5c3RlbSBFdmVudDxici8+ZS5nLiBhZ2VudC5jcmVhdGVkXSAtLT58bWF0Y2h8IEVUW0V2ZW50IFRyaWdnZXI8YnIvPmNvbmRpdGlvbnMgY2hlY2tdCiAgICBFVCAtLT4gV0ZbV29ya2Zsb3cgRXhlY3V0aW9uXQ=="></div><p>For the full list of system events, see the <a href="/open-agent-orchestra/reference/events.html">Events Reference</a>.</p><p><strong>Event data conditions</strong> — filter by matching key-value pairs (e.g., <code>scope = workspace</code>, <code>agentName = &quot;MyAgent&quot;</code>).</p><h2 id="engine-execution" tabindex="-1">Engine &amp; Execution <a class="header-anchor" href="#engine-execution" aria-label="Permalink to &quot;Engine &amp; Execution&quot;">​</a></h2><p>For details on the workflow engine, controller, execution pipeline, retry mechanism, and concurrency, see <a href="/open-agent-orchestra/concepts/workflow-engine.html">Workflow Engine &amp; Controller</a>.</p><p>For what happens inside each step — Jinja2 templating, variable resolution, Git checkout, Copilot session setup, tool loading, and cleanup — see <a href="/open-agent-orchestra/concepts/agent-steps.html">Agent Steps</a>.</p>',6))])}const A=p(g,[["render",u]]);export{y as __pageData,A as default};
